#include<stdio.h>
typedef long long int L;
int k;
L i,s,n;
int check(L m)
{
    s=0;
    for(i=m;i>0;i=i/k)
    {
        s=s+i;
        if(s>=n) return 1;
    }
    return 0;
}
int main()
{
    L low=1,high,mid;
    scanf("%I64d%d",&n,&k);
    high=n;
    while(low<high)
    {
        mid=(low+high)/2;
        if(check(mid))
        high=mid;
        else
        low=mid+1;
    }
    printf("%I64d\n",high);
    return 0;
}

