fn is_sufficient(v: u64, n: u64, k: u64) -> bool {
    let summand_count = ((v as f64).log(k as f64).trunc() + 1_f64) as usize;
    // dbg!(summand_count);
    let sum: u64 = (0..summand_count).map(|x| v / k.checked_pow(x as u32).unwrap()).sum();
    // dbg!(sum);
    sum >= n
}

fn solve(n: u64, k: u64) -> u64 {
    let mut l: u64 = 1;
    let mut r: u64 = n + 1;
    while r - l > 2 {
        let m = l + (r - l) / 2;
        // dbg!(l, m, r);
        if is_sufficient(m, n, k) {
            // dbg!("YES");
            r = m + 1;
        } else {
            // dbg!("NO");
            l = m;
        }
    }
    // dbg!(is_sufficient(4, n, k));
    if is_sufficient(l, n, k) {l} else {l + 1}
}

fn main() {
    let (n, k) = {
        let mut buf = String::new();
        std::io::stdin().read_line(&mut buf).unwrap();
        let mut n_k = buf.trim().split_whitespace().map(|x| x.parse::<u64>().unwrap());
        let n = n_k.next().unwrap();
        let k = n_k.next().unwrap();
        (n, k)
    };

    println!("{}", solve(n, k));
}
